     5→//! Notch and Chalk - Steeplechase commit formatting
     6→//!
     7→//! Provides message formatting for JJ-aware git commits that record session history:
     8→//! - jjx_notch: Standard commit with heat/pace context prefix
     9→//! - jjx_chalk: Empty commit marking a steeplechase event (pace-level)
    10→//! - Heat-level commits: nominate, slate, rail, tally, draft, retire
    11→//!
    12→//! Commit format: `jjb:HALLMARK:IDENTITY:ACTION: message`
    13→//! - HALLMARK: Version identifier (NNNN or NNNN-xxxxxxx)
    14→//! - IDENTITY: ₢CORONET for pace-level, ₣FIREMARK for heat-level
    15→//! - ACTION: Single letter code (required for all commits)
    16→//!
    17→//! The actual commit execution is handled by vorc_commit in the vok crate.
    18→//! This module exports formatting functions that the CLI handlers use.
    19→
    20→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_CORONET_PREFIX as CORONET_PREFIX, JJRF_FIREMARK_PREFIX as FIREMARK_PREFIX};
    21→
    22→/// Commit message prefix
    23→pub const JJRN_COMMIT_PREFIX: &str = "jjb";
    24→
    25→
    26→/// Pace-level chalk markers (single-letter codes)
    27→/// - A = APPROACH: proposed approach before work begins
    28→/// - W = WRAP: pace completion summary
    29→/// - F = FLY: autonomous execution began (bridled pace)
    30→/// - B = BRIDLE: pace transitioned to bridled state
    31→/// - d = discussion: significant decision (lowercase, can be heat-level too)
    32→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    33→pub enum jjrn_ChalkMarker {
    34→    Approach,
    35→    Wrap,
    36→    Fly,
    37→    Bridle,
    38→    Discussion,
    39→}
    40→
    41→impl jjrn_ChalkMarker {
    42→    /// Parse marker from string (accepts both single letter and full word)
    43→    pub fn jjrn_parse(s: &str) -> Result<Self, String> {
    44→        match s {
    45→            "A" | "a" | "APPROACH" | "approach" | "Approach" => Ok(jjrn_ChalkMarker::Approach),
    46→            "W" | "w" | "WRAP" | "wrap" | "Wrap" => Ok(jjrn_ChalkMarker::Wrap),
    47→            "F" | "f" | "FLY" | "fly" | "Fly" => Ok(jjrn_ChalkMarker::Fly),
    48→            "B" | "b" | "BRIDLE" | "bridle" | "Bridle" => Ok(jjrn_ChalkMarker::Bridle),
    49→            "d" | "D" | "DISCUSSION" | "discussion" | "Discussion" => Ok(jjrn_ChalkMarker::Discussion),
    50→            _ => Err(format!(
    51→                "Invalid marker type '{}'. Valid: A(pproach), W(rap), F(ly), B(ridle), d(iscussion)",
    52→                s
    53→            )),
    54→        }
    55→    }
    56→
    57→    /// Get single-letter code for commit message
    58→    pub fn jjrn_code(&self) -> char {
    59→        match self {
    60→            jjrn_ChalkMarker::Approach => 'A',
    61→            jjrn_ChalkMarker::Wrap => 'W',
    62→            jjrn_ChalkMarker::Fly => 'F',
    63→            jjrn_ChalkMarker::Bridle => 'B',
    64→            jjrn_ChalkMarker::Discussion => 'd',
    65→        }
    66→    }
    67→
    68→    /// Get full display string for the marker (for user-facing output)
    69→    pub fn jjrn_as_str(&self) -> &'static str {
    70→        match self {
    71→            jjrn_ChalkMarker::Approach => "APPROACH",
    72→            jjrn_ChalkMarker::Wrap => "WRAP",
    73→            jjrn_ChalkMarker::Fly => "FLY",
    74→            jjrn_ChalkMarker::Bridle => "BRIDLE",
    75→            jjrn_ChalkMarker::Discussion => "discussion",
    76→        }
    77→    }
    78→
    79→    /// Returns true if this marker type requires a pace to be specified
    80→    pub fn jjrn_requires_pace(&self) -> bool {
    81→        match self {
    82→            jjrn_ChalkMarker::Approach | jjrn_ChalkMarker::Wrap | jjrn_ChalkMarker::Fly | jjrn_ChalkMarker::Bridle => true,
    83→            jjrn_ChalkMarker::Discussion => false,
    84→        }
    85→    }
    86→}
    87→
    88→/// Heat-level action codes (single-letter codes)
    89→/// - N = Nominate: create new heat
    90→/// - S = Slate: add new pace
    91→/// - r = rail: reorder paces (lowercase)
    92→/// - T = Tally: add tack to pace
    93→/// - D = Draft: move pace between heats (uppercase, rare)
    94→/// - R = Retire: archive heat (uppercase)
    95→/// - f = furlough: change heat status or rename (lowercase)
    96→/// - G = Garland: celebrate completed heat, create continuation (uppercase)
    97→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    98→pub enum jjrn_HeatAction {
    99→    Nominate,
   100→    Slate,
   101→    Rail,
   102→    Tally,
   103→    Draft,
   104→    Retire,
   105→    Furlough,
   106→    Garland,
   107→}
   108→
   109→impl jjrn_HeatAction {
   110→    /// Get single-letter code for commit message
   111→    pub fn jjrn_code(&self) -> char {
   112→        match self {
   113→            jjrn_HeatAction::Nominate => 'N',
   114→            jjrn_HeatAction::Slate => 'S',
   115→            jjrn_HeatAction::Rail => 'r',
   116→            jjrn_HeatAction::Tally => 'T',
   117→            jjrn_HeatAction::Draft => 'D',
   118→            jjrn_HeatAction::Retire => 'R',
   119→            jjrn_HeatAction::Furlough => 'f',
   120→            jjrn_HeatAction::Garland => 'G',
   121→        }
   122→    }
   123→
   124→    /// Get full display string (for user-facing output)
   125→    pub fn jjrn_as_str(&self) -> &'static str {
   126→        match self {
   127→            jjrn_HeatAction::Nominate => "nominate",
   128→            jjrn_HeatAction::Slate => "slate",
   129→            jjrn_HeatAction::Rail => "rail",
   130→            jjrn_HeatAction::Tally => "tally",
   131→            jjrn_HeatAction::Draft => "draft",
   132→            jjrn_HeatAction::Retire => "retire",
   133→            jjrn_HeatAction::Furlough => "furlough",
   134→            jjrn_HeatAction::Garland => "garland",
   135→        }
   136→    }
   137→}
   138→
   139→/// Format the notch prefix: jjb:HALLMARK:₢CORONET:n:
   140→///
   141→/// Returns the prefix string to prepend to commit messages for JJ-aware commits.
   142→/// The coronet provides full context (embeds parent firemark).
   143→pub fn jjrn_format_notch_prefix(coronet: &Coronet) -> String {
   144→    let hallmark = vvc::vvcc_get_hallmark();
   145→    let identity = format!("{}{}", CORONET_PREFIX, coronet.jjrf_as_str());
   146→    // Special case: subject="" produces "...:n: " and caller appends real message
   147→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, "n", "", None)
   148→}
   149→
   150→/// Format the chalk message: jjb:HALLMARK:₢CORONET:X: description
   151→///
   152→/// Returns the full commit message for a chalk (steeplechase marker) commit.
   153→pub fn jjrn_format_chalk_message(coronet: &Coronet, marker: jjrn_ChalkMarker, description: &str) -> String {
   154→    let hallmark = vvc::vvcc_get_hallmark();
   155→    let identity = format!("{}{}", CORONET_PREFIX, coronet.jjrf_as_str());
   156→    let action = marker.jjrn_code().to_string();
   157→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, &action, description, None)
   158→}
   159→
   160→/// Format a heat-level discussion message (no pace context): jjb:HALLMARK:₣XX:d: description
   161→pub fn jjrn_format_heat_discussion(firemark: &Firemark, description: &str) -> String {
   162→    let hallmark = vvc::vvcc_get_hallmark();
   163→    let identity = format!("{}{}", FIREMARK_PREFIX, firemark.jjrf_as_str());
   164→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, "d", description, None)
   165→}
   166→
   167→/// Format a heat-level action message: jjb:HALLMARK:₣XX:X: description
   168→///
   169→/// Used for nominate, slate, rail, tally, draft, retire operations.
   170→pub fn jjrn_format_heat_message(firemark: &Firemark, action: jjrn_HeatAction, description: &str) -> String {
   171→    let hallmark = vvc::vvcc_get_hallmark();
   172→    let identity = format!("{}{}", FIREMARK_PREFIX, firemark.jjrf_as_str());
   173→    let action_code = action.jjrn_code().to_string();
   174→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, &action_code, description, None)
   175→}
   176→
   177→/// Format a bridle message: jjb:HALLMARK:₢CORONET:B: {agent} | {silks}
   178→///
   179→/// Creates the subject line for a B (bridle) commit.
   180→/// Body should contain the full direction text.
   181→pub fn jjrn_format_bridle_message(coronet: &Coronet, agent: &str, silks: &str) -> String {
   182→    let hallmark = vvc::vvcc_get_hallmark();
   183→    let identity = format!("{}{}", CORONET_PREFIX, coronet.jjrf_as_str());
   184→    let subject = format!("{} | {}", agent, silks);
   185→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, "B", &subject, None)
   186→}
   187→
   188→/// Format a landing message: jjb:HALLMARK:₢CORONET:L: {agent} landed
   189→///
   190→/// Creates the subject line for an L (landing) commit.
   191→/// Body should contain the agent completion report.
   192→pub fn jjrn_format_landing_message(coronet: &Coronet, agent: &str) -> String {
   193→    let hallmark = vvc::vvcc_get_hallmark();
   194→    let identity = format!("{}{}", CORONET_PREFIX, coronet.jjrf_as_str());
   195→    let subject = format!("{} landed", agent);
   196→    vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity, "L", &subject, None)
   197→}
   198→
   199→

